import zlib, base64

def _decode(data_list, keys):
    data_list = [int(x) for x in data_list]
    b = bytes(data_list)
    for key in reversed(keys):
        key = key & 0xFF
        b = b[::-1]
        b = bytes([x ^ key for x in b])
        b = base64.b64decode(b)
        b = zlib.decompress(b)
    return b.decode('utf-8')

